use vta
SELECT labor_time_card.EMPLOYEE_ID, labor_employee.PAYROLL_EMP_ID, labor_employee.FIRST_NAME, labor_employee.LAST_NAME, LABOR_TIME_ENTRY.TIME_CARD_ID, labor_time_Card.PAY_YEAR, labor_time_card.PAY_PERIOD, labor_time_entry.START_DATE as CLOCK_IN, labor_time_entry.END_DATE as CLOCK_OUT, BREAKS.BREAK_HOURS * 24 as BREAK_HOURS, DATEADD(week, DATEDIFF(week, 0, labor_time_entry.start_date ), 0) -1 as beg_week,  (CASE WHEN LABOR_TIME_ENTRY.END_DATE IS NOT NULL THEN  CONVERT(DECIMAL(10, 4), LABOR_TIME_ENTRY.END_DATE) ELSE CONVERT(DECIMAL(10, 4), GETDATE()) END- CONVERT(DECIMAL(10, 4), LABOR_TIME_ENTRY.START_DATE))*24 as TOTAL_HOURS, (CASE WHEN LABOR_TIME_ENTRY.END_DATE IS NOT NULL THEN  CONVERT(DECIMAL(10, 4), LABOR_TIME_ENTRY.END_DATE) ELSE CONVERT(DECIMAL(10, 4), GETDATE()) END- CONVERT(DECIMAL(10, 4), LABOR_TIME_ENTRY.START_DATE)- isnull(breaks.break_hours,0)) *24 AS PAID_HOURS FROM  VTA.dbo.LABOR_TIME_ENTRY  LEFT OUTER JOIN (SELECT LABOR_TIME_ENTRY_BREAK.TIME_CARD_ID, LABOR_TIME_ENTRY_BREAK.LINE_NO, SUM(CONVERT(DECIMAL(10,4),CASE WHEN LABOR_TIME_ENTRY_BREAK.BREAK_END IS NOT NULL THEN LABOR_TIME_ENTRY_BREAK.BREAK_END ELSE GETDATE() END)- CONVERT(DECIMAL(10,4), LABOR_TIME_ENTRY_BREAK.BREAK_START)) AS BREAK_HOURS FROM VTA.dbo.LABOR_TIME_ENTRY_BREAK  GROUP BY LABOR_TIME_ENTRY_BREAK.TIME_CARD_ID, LABOR_TIME_ENTRY_BREAK.LINE_NO ) AS BREAKS ON BREAKS.TIME_CARD_ID=LABOR_TIME_ENTRY.TIME_CARD_ID AND BREAKS.LINE_NO=LABOR_TIME_ENTRY.LINE_NO inner join labor_time_card on labor_time_entry.TIME_CARD_ID = labor_time_card.TIME_CARD_ID inner join labor_employee on labor_time_card.EMPLOYEE_ID = labor_employee.EMPLOYEE_ID WHERE  LABOR_TIME_ENTRY.TIME_CARD_ID in ( SELECT LABOR_TIME_CARD.TIME_CARD_ID FROM  VTA.dbo.LABOR_TIME_CARD  WHERE PAY_YEAR = '2021' ) and (LABOR_TIME_ENTRY.START_DATE >= '2021-01-01' or LABOR_TIME_ENTRY.END_DATE >= '2021-01-01') and (LABOR_TIME_ENTRY.START_DATE <= '2022-02-28' or LABOR_TIME_ENTRY.END_DATE <= '2022-02-28') ORDER BY  employee_id, TIME_CARD_ID, LABOR_TIME_ENTRY.LINE_NO